## **12. Complete Example - Creating and Using an Agent with Tools**

```csharp
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;
using System.Text.Json;

// 1. Create tools
var weatherTool = AIFunctionFactory.Create(
    (string location) => 
    {
        return Task.FromResult<object?>(
            $"The weather in {location} is sunny.");
    },
    "get_weather",
    "Gets the current weather for a location");

var addTool = AIFunctionFactory.Create(
    (int a, int b) => Task.FromResult<object?>(a + b),
    "add",
    "Adds two numbers");

var tools = new List<AITool> { weatherTool, addTool };

// 2. Create IChatClient (e.g., OpenAI)
var openaiClient = new OpenAIClient("api-key");
var chatClient = openaiClient.AsChatClient("gpt-4");

// 3. Create agent
var loggerFactory = LoggerFactory.Create(builder => builder.AddConsole());
var agent = new ChatClientAgent(
    chatClient: chatClient,
    instructions: "You are a helpful assistant with access to tools.",
    name: "MyAssistant",
    description: "An assistant that can get weather and do math",
    tools: tools,
    loggerFactory: loggerFactory,
    services: null);

// 4. Create session
AgentSession? session = null;

// 5. Run agent
var messages = new[]
{
    new ChatMessage(ChatRole.User, 
        "What is the weather in Seattle and what is 5 + 3?")
};

var response = await agent.RunAsync(
    messages,
    session,
    new ChatClientAgentRunOptions(),
    CancellationToken.None);

// 6. Process response
foreach (var message in response.Messages)
{
    Console.WriteLine($"{message.Role}: {message.TextContent}");
}

// 7. Stream example
await foreach (var update in agent.RunStreamingAsync(
    "Tell me a joke",
    session,
    new ChatClientAgentRunOptions(),
    CancellationToken.None))
{
    // Handle streaming updates
    Console.WriteLine(update);
}
```

